import * as XLSX from 'xlsx';
import dayjs from 'dayjs';
import customParseFormat from 'dayjs/plugin/customParseFormat.js';

dayjs.extend(customParseFormat);

export const processCombinedData = (csvData, excelRaw, proyectadoManual = 239000) => {
  // --- 1. PROCESAR EXCEL (EASY DOCKING) ---
  const workbook = XLSX.read(excelRaw, { type: 'array' });
  const sheet = workbook.Sheets[workbook.SheetNames[0]];
  const rawMatrix = XLSX.utils.sheet_to_json(sheet, { header: 1 });

  // Headers en fila 4 (índice 3)
  const headers = rawMatrix[3]?.map(h => String(h || "").trim()) || []; 
  const dataRows = rawMatrix.slice(4);

  const easyDockingClean = dataRows.map(row => {
    let obj = {};
    headers.forEach((h, i) => obj[h] = row[i]);
    return obj;
  }).filter(item => 
    String(item['TIPO DE OPERACION'] || "").toUpperCase().includes("DESCARGA") && 
    String(item['Accion'] || "").toLowerCase() === "add"
  );

  // SUMA DE UNIDADES FÍSICAS (ARRIBADOS)
  const totalArribadosFisicos = easyDockingClean.reduce((acc, curr) => {
    return acc + (parseFloat(curr['CANT PAQUETES']) || 0);
  }, 0);

  // --- 2. PROCESAR CSV (TMS - SHIPMENT ID) ---
  const totalPiezasSistema = csvData.filter(d => d['Shipment ID']).length;
  const totalBipeadasReal = csvData.filter(d => d['Labeling Date Printed']).length;

  // --- 3. LÓGICA DE TIEMPO (FÓRMULA EXCEL 22:00HS) ---
  const ahora = dayjs();
  const horaCierre = dayjs().set('hour', 22).set('minute', 0).set('second', 0);

  // Calculamos la diferencia en horas decimales (como el *24 del Excel)
  let horasRestantes = horaCierre.diff(ahora, 'hour', true);

  // Seguridad: si ya pasó las 22:00, usamos 0.5 para no dividir por cero
  if (horasRestantes <= 0) horasRestantes = 0.5;

  // FÓRMULA EXCEL: (Proyectado - Bipeado) / Horas_Restantes
  const objXHora = Math.round((proyectadoManual - totalPiezasSistema) / horasRestantes);

  // --- 4. CONFIGURAR GRÁFICA Y TABLA (05:00 A 23:00) ---
  const franjas = [];
  for (let i = 5; i <= 23; i++) {
    franjas.push(`${i.toString().padStart(2, '0')}:00`);
  }

  const chartMap = {};
  franjas.forEach(h => chartMap[h] = { hora: h, arribo: 0, bipeo: 0 });

  // Llenar Arribos (Excel)
  easyDockingClean.forEach(row => {
    if (row['Fecha y Hora']) {
      const hora = dayjs(row['Fecha y Hora']).format('HH:00');
      if (chartMap[hora]) chartMap[hora].arribo += (parseFloat(row['CANT PAQUETES']) || 0);
    }
  });

  // Llenar Bipeos (CSV)
  csvData.forEach(row => {
    if (row['Labeling Date Printed']) {
      const hora = dayjs(row['Labeling Date Printed'], "DD/MM/YYYY HH:mm:ss").format('HH:00');
      if (chartMap[hora]) chartMap[hora].bipeo++;
    }
  });

  // --- 5. RESULTADO FINAL (KPIs) ---
  return {
    kpis: {
      proyectado: proyectadoManual.toLocaleString(),
      arribados: totalArribadosFisicos.toLocaleString(), // Y6 en tu Excel
      total: totalPiezasSistema.toLocaleString(),      // Y7 en tu Excel

      // Métrica calculada con tu fórmula (Obj x Hora)
      descargaHora: objXHora > 0 ? objXHora.toLocaleString() : "FINALIZADO",

      // Deltas
      arribadoBipeado: (totalArribadosFisicos - totalPiezasSistema).toLocaleString(),
      proyectadoBipeado: (proyectadoManual - totalPiezasSistema).toLocaleString(),

      // Porcentajes
      pArribado: Math.round((totalArribadosFisicos / proyectadoManual) * 100) || 0,
      pBipeo: Math.round((totalPiezasSistema / proyectadoManual) * 100) || 0,

      velocidadReal: 90 // Este es el SPR real que calcularemos por hora después
    },
    chartData: Object.values(chartMap),
    tableData: franjas.map(h => ({
      intervalo: h,
      etiquetado: Math.round(proyectadoManual / franjas.length),
      piezas: chartMap[h].bipeo,
      usuarios: 12
    })),
    matrix: {
      chasis: easyDockingClean.filter(d => String(d['TRANSPORTE']).includes('Chasis')).length,
      camioneta: easyDockingClean.filter(d => String(d['TRANSPORTE']).toLowerCase().includes('camioneta')).length,
      semi: easyDockingClean.filter(d => String(d['TRANSPORTE']).includes('Semi')).length
    }
  };
};
